tool_input.content:
import { NextResponse } from 'next/server';

// X/Twitter API v2 — Recent Search
// Requires TWITTER_BEARER_TOKEN env var (Basic tier $100/mo or Academic Research)
// Falls back gracefully if not configured

interface Tweet {
  text: string;
  url: string;
  created_at: string;
  author: string;
}

export async function GET() {
  const token = process.env.TWITTER_BEARER_TOKEN;

  if (!token) {
    // No token configured — return empty so news ribbon falls back to RSS
    return NextResponse.json(
      { items: [], note: 'TWITTER_BEARER_TOKEN not configured', timestamp: new Date().toISOString() },
      { headers: { 'Cache-Control': 'public, s-maxage=60' } }
    );
  }

  try {
    const query = encodeURIComponent(
      '(venezuela oil OR PDVSA OR "venezuelan crude" OR "venezuela production") -is:retweet lang:en'
    );
    const url = `https://api.twitter.com/2/tweets/search/recent?query=${query}&max_results=10&sort_order=relevancy&tweet.fields=created_at,author_id,public_metrics&expansions=author_id&user.fields=username,name`;

    const res = await fetch(url, {
      headers: { Authorization: `Bearer ${token}` },
      next: { revalidate: 900 }, // 15-min cache
    });

    if (!res.ok) {
      const err = await res.text();
      console.error('[api/x] Twitter API error:', res.status, err);
      return NextResponse.json(
        { items: [], error: `Twitter API ${res.status}`, timestamp: new Date().toISOString() },
        { status: 200 } // Don't break the ribbon
      );
    }

    const data = await res.json();
    const users = new Map<string, string>();
    if (data.includes?.users) {
      for (const u of data.includes.users) {
        users.set(u.id, `@${u.username}`);
      }
    }

    const items: Tweet[] = (data.data || []).map((t: { text: string; id: string; created_at: string; author_id: string }) => ({
      text: t.text.replace(/https:\/\/t\.co\/\S+/g, '').trim().substring(0, 140),
      url: `https://x.com/i/status/${t.id}`,
      created_at: t.created_at,
      author: users.get(t.author_id) || '',
    }));

    return NextResponse.json(
      { items, timestamp: new Date().toISOString() },
      { headers: { 'Cache-Control': 'public, s-maxage=900, stale-while-revalidate=300' } }
    );
  } catch (err) {
    console.error('[api/x] fetch failed:', err);
    return NextResponse.json(
      { items: [], error: 'X feed unavailable', timestamp: new Date().toISOString() },
      { status: 200 }
    );
  }
}

import { NextResponse } from 'next/server';

interface NewsItem {
  title: string;
  link: string;
  pubDate: string;
  source: string;
}

function parseRSS(xml: string): NewsItem[] {
  const items: NewsItem[] = [];
  const itemMatches = xml.matchAll(/<item>([\s\S]*?)<\/item>/g);

  for (const match of itemMatches) {
    const block = match[1];
    const title = block.match(/<title><!\[CDATA\[(.*?)\]\]><\/title>/)?.[1]
      ?? block.match(/<title>(.*?)<\/title>/)?.[1]
      ?? '';
    const link = block.match(/<link>(.*?)<\/link>/)?.[1]
      ?? block.match(/<guid>(.*?)<\/guid>/)?.[1]
      ?? '';
    const pubDate = block.match(/<pubDate>(.*?)<\/pubDate>/)?.[1] ?? '';

    // Google News encodes source after last " - "
    const titleParts = title.split(' - ');
    const source = titleParts.length > 1 ? titleParts[titleParts.length - 1].trim() : '';
    const cleanTitle = titleParts.slice(0, -1).join(' - ').trim() || title;

    if (cleanTitle && link) {
      items.push({ title: cleanTitle, link, pubDate, source });
    }
  }
  return items;
}

const RSS_FEEDS = [
  // Multiple queries for broader, fresher coverage
  'https://news.google.com/rss/search?q=venezuela+oil+production+sanctions&hl=en-US&gl=US&ceid=US:en',
  'https://news.google.com/rss/search?q=PDVSA+chevron+venezuela&hl=en-US&gl=US&ceid=US:en',
  'https://news.google.com/rss/search?q=brent+crude+oil+price+hormuz&hl=en-US&gl=US&ceid=US:en',
  'https://news.google.com/rss/search?q=oil+market+OPEC+production&hl=en-US&gl=US&ceid=US:en',
];

export async function GET() {
  try {
    // Fetch all feeds in parallel
    const results = await Promise.allSettled(
      RSS_FEEDS.map(url =>
        fetch(url, {
          headers: {
            'User-Agent': 'Mozilla/5.0 (compatible; vnzla-oil-dashboard/1.0)',
            Accept: 'application/rss+xml, application/xml, text/xml',
          },
          next: { revalidate: 1800 }, // 30-min cache per feed
        }).then(r => r.ok ? r.text() : '')
      )
    );

    // Collect and deduplicate
    const seen = new Set<string>();
    const allItems: NewsItem[] = [];

    for (const result of results) {
      if (result.status === 'fulfilled' && result.value) {
        for (const item of parseRSS(result.value)) {
          const key = item.title.toLowerCase().substring(0, 60);
          if (!seen.has(key)) {
            seen.add(key);
            allItems.push(item);
          }
        }
      }
    }

    // Sort by date descending, take top 15
    allItems.sort((a, b) => new Date(b.pubDate).getTime() - new Date(a.pubDate).getTime());
    const items = allItems.slice(0, 15);

    return NextResponse.json(
      { items, timestamp: new Date().toISOString() },
      { headers: { 'Cache-Control': 'public, s-maxage=1800, stale-while-revalidate=300' } }
    );
  } catch (err) {
    console.error('[api/news] fetch failed:', err);
    return NextResponse.json(
      { items: [], error: 'News feed unavailable', timestamp: new Date().toISOString() },
      { status: 503 }
    );
  }
}

