    if(f==='spill')show=m._isSpill;
    else if(f==='field')show=!m._isSpill&&d.cat==='field';
    else if(f==='gas')show=!m._isSpill&&d.cat==='gas';
    else if(f==='infra')show=!m._isSpill&&d.cat==='infra';
    else if(f==='gl50a')show=!m._isSpill&&gl50aOps.some(function(op){return d.op&&d.op.includes(op);});
    else if(f==='excluded')show=!m._isSpill&&d.ofac&&(d.ofac.includes('EXCLUDED')||d.ofac.includes('disavowed'));
    // all = show everything including spills
    m.setStyle({fillOpacity:show?.85:.08,opacity:show?.8:.08});
    if(m._isSpill){m.setRadius(show?7:2);}
    else{
      var bpd=m._data.bpd||0;
      if(show)m.setRadius(bpd>100000?10:bpd>50000?8:bpd>10000?6:d.cat==='infra'?9:5);
      else m.setRadius(3);
    }
  });
}

