// Fetch EIA production
try {
  var pr = await fetch('/api/production');
  if(pr.ok) {
    var pd = await pr.json();
    if(pd.data && pd.data.length > 0) {
      var latest = pd.data[0];
      var prev = pd.data[1];
      var kpi0 = document.querySelectorAll('.kpi')[0];
      if(kpi0) {
        // Format period: "2025-12" → "Dec 2025"
        var parts = latest.period.split('-');
        var months = ['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec'];
        var periodLabel = months[parseInt(parts[1])-1] + ' ' + parts[0];
        kpi0.querySelector('.kpi-l').textContent = 'Production (' + periodLabel + ')';
        kpi0.querySelector('.kpi-v').innerHTML = Math.round(latest.value) + '<span style="font-size:11px;color:var(--t3)">K bpd</span>';
        kpi0.querySelector('.kpi-s').textContent = pd.source === 'eia' ? 'EIA (live)' : 'Estimate';
        // MoM change
        if(prev) {
          var chg = ((latest.value - prev.value) / prev.value * 100).toFixed(1);
          var prevLabel = months[parseInt(prev.period.split('-')[1])-1];
          var chgEl = kpi0.querySelector('.kpi-c');
          chgEl.textContent = (chg >= 0 ? '+' : '') + chg + '% from ' + prevLabel + ' (' + Math.round(prev.value) + 'K)';
          chgEl.className = 'kpi-c ' + (chg >= 0 ? 't-up' : 't-dn');
        }
      }
    }
  }
} catch(e) { console.log('EIA fetch failed:', e); }

