// Live production data layers — populated by /api/production fetch
var liveEia={};    // period → value (EIA official only)
var liveEst={};    // period → value (CEIC/TE/Kpler estimates)
var liveDataLoaded=false;

function labelToKey(lbl){
  var months=['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec'];
  var mm=lbl.replace('E','').trim().match(/([A-Z][a-z]{2})\s+(\d{2})/);
  if(mm)return '20'+mm[2]+'-'+String(months.indexOf(mm[1])+1).padStart(2,'0');
  if(/^\d{4}$/.test(lbl.replace('E','')))return lbl.replace('E','');
  var qm=lbl.replace('E','').trim().match(/Q(\d)\s+(\d{2})/);
  if(qm)return '20'+qm[2]+'-Q'+qm[1];
  return null;
}

function getDataForView(){
  const d=curGran==='A'?dataA:curGran==='Q'?dataQ:dataM;
  let startIdx=0;
  if(curRange!=='MAX'){
    const yearsBack={'1Y':1,'3Y':3,'5Y':5}[curRange]||1;
    const lastYear=labelToYear(d.labels[d.labels.length-1]);
    const cutoff=lastYear-yearsBack;
    startIdx=d.labels.findIndex(l=>labelToYear(l)>=cutoff);
    if(startIdx<0)startIdx=0;
  }
  let labels=d.labels.slice(startIdx);
  let vals=d.vals.slice(startIdx);
  let notes=d.notes.slice(startIdx);
  if(!projOn){
    let lastReal=labels.length-1;
    while(lastReal>0&&vals[lastReal]===null)lastReal--;
    labels=labels.slice(0,lastReal+1);
    vals=vals.slice(0,lastReal+1);
    notes=notes.slice(0,lastReal+1);
  }

  // Before live data loads, show single line (hardcoded vals as blended)
  if(!liveDataLoaded){
    return {labels,vals,notes,scenario:mkScenario(labels,vals,curSc),
      eiaLine:vals.slice(), estLine:new Array(labels.length).fill(null), blendLine:vals.slice()};
  }

  // After live data: EIA line = hardcoded baseline overwritten by live EIA where available
  // Estimate line = only where live estimates exist (recent months)
  // Blended = average where both exist, else whichever is available
  var eiaLine=vals.slice(); // start with hardcoded as EIA baseline
  var estLine=new Array(labels.length).fill(null);
  var blendLine=vals.slice(); // start with hardcoded

  labels.forEach(function(lbl,i){
    var key=labelToKey(lbl);
    if(!key)return;
    var eV=null,esV=null;

    if(key.length===4){ // annual — find latest month
      for(var mi=12;mi>=1;mi--){
        var mk=key+'-'+String(mi).padStart(2,'0');
        if(!eV&&liveEia[mk])eV=liveEia[mk];
        if(!esV&&liveEst[mk])esV=liveEst[mk];
      }
    } else if(key.includes('-Q')){ // quarterly
      var qy='20'+key.split('-Q')[0].slice(2);var qn=parseInt(key.split('-Q')[1]);
      var startM=(qn-1)*3+1;
      for(var mi=startM+2;mi>=startM;mi--){
        var mk=qy+'-'+String(mi).padStart(2,'0');
        if(!eV&&liveEia[mk])eV=liveEia[mk];
        if(!esV&&liveEst[mk])esV=liveEst[mk];
      }
    } else { // monthly
      eV=liveEia[key]||null;
      esV=liveEst[key]||null;
    }

    // Overwrite EIA line with live EIA if available
    if(eV)eiaLine[i]=eV;
    // Estimate line only shows where estimates exist
    if(esV)estLine[i]=esV;
    // Blended: average if both, else best available
    if(eV&&esV)blendLine[i]=Math.round((eV+esV)/2);
    else if(eV)blendLine[i]=eV;
    else if(esV)blendLine[i]=esV;
    // else keep hardcoded val
  });

  return {labels,vals,notes,scenario:mkScenario(labels,blendLine,curSc),eiaLine,estLine,blendLine};
